#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>

/*
 * PKI Certificate Structure Implementation in C
 * Demonstrates: Certificate fields, RSA signing, verification
 * For educational purposes - simplified implementation
 */

#define MAX_NAME_LEN 64
#define MAX_DN_LEN 256
#define SHA256_SIZE 32
#define RSA_KEY_SIZE 2048

// ============================================
// Certificate Structure Definition
// ============================================

typedef struct {
 char subject[MAX_NAME_LEN]; // Who owns this certificate
 char issuer[MAX_NAME_LEN]; // Who signed this certificate
 unsigned char public_key[RSA_KEY_SIZE]; // Owner's public key
 unsigned char signature[256]; // CA's digital signature
 time_t valid_from; // Certificate validity start
 time_t valid_until; // Certificate validity end
 unsigned int serial_number; // Unique certificate identifier
 int is_ca; // Is this a CA certificate?
} Certificate;

// Simplified hash structure
typedef struct {
 unsigned char hash[SHA256_SIZE];
} SHA256Hash;

// ============================================
// Certificate Creation Functions
// ============================================

void init_certificate(Certificate *cert, const char *subject, const char *issuer) {
 strncpy(cert->subject, subject, MAX_NAME_LEN - 1);
 strncpy(cert->issuer, issuer, MAX_NAME_LEN - 1);
 cert->serial_number = (unsigned int)time(NULL);
 cert->valid_from = time(NULL);
 cert->valid_until = time(NULL) + (365 * 24 * 60 * 60); // 1 year validity
 cert->is_ca = 0;

 // In real implementation, would generate actual RSA key here
 memset(cert->public_key, 0, RSA_KEY_SIZE);
 memset(cert->signature, 0, 256);
}

void print_certificate_info(Certificate *cert) {
 printf("\n=== Certificate Information ===\n");
 printf("Subject: %s\n", cert->subject);
 printf("Issuer: %s\n", cert->issuer);
 printf("Serial: %u\n", cert->serial_number);
 printf("Valid: %s", ctime(&cert->valid_from));
 printf(" to: %s", ctime(&cert->valid_until));
 printf("CA: %s\n", cert->is_ca ? "Yes" : "No");
 printf("================================\n\n");
}

// ============================================
// Simplified Hash and Signature Functions
// ============================================

/*
 * Simplified SHA-256 hash computation
 * In production, use OpenSSL or similar library
 */
SHA256Hash compute_certificate_hash(Certificate *cert) {
 SHA256Hash hash_result;

 // Create a simple hash from certificate fields
 // Real implementation would use proper SHA-256
 unsigned char buffer[MAX_DN_LEN + sizeof(time_t) * 2 + sizeof(int)];
 int offset = 0;

 memcpy(buffer + offset, cert->subject, strlen(cert->subject));
 offset += strlen(cert->subject);

 memcpy(buffer + offset, cert->issuer, strlen(cert->issuer));
 offset += strlen(cert->issuer);

 memcpy(buffer + offset, &cert->valid_from, sizeof(time_t));
 offset += sizeof(time_t);

 memcpy(buffer + offset, &cert->serial_number, sizeof(unsigned int));

 // Simplified hash calculation
 unsigned int hash_val = 0;
 for (int i = 0; i < offset; i++) {
 hash_val = hash_val * 31 + buffer[i];
 }

 memset(hash_result.hash, 0, SHA256_SIZE);
 memcpy(hash_result.hash, &hash_val, sizeof(unsigned int));

 return hash_result;
}

/*
 * Simulated RSA signing (in reality uses OpenSSL)
 * Signs the hash using CA's private key
 */
void sign_certificate(Certificate *cert, unsigned char *ca_private_key) {
 SHA256Hash cert_hash = compute_certificate_hash(cert);

 // In production: RSA_private_encrypt(hash, private_key, signature)
 // This is a simplified simulation
 for (int i = 0; i < 256; i++) {
 cert->signature[i] = cert_hash.hash[i % SHA256_SIZE] ^ ca_private_key[i];
 }

 printf("[SIGN] Certificate signed by CA\n");
}

/*
 * Verify certificate signature using CA's public key
 * Returns 1 if valid, 0 if invalid
 */
int verify_certificate_signature(Certificate *cert, unsigned char *ca_public_key) {
 SHA256Hash computed_hash = compute_certificate_hash(cert);

 // In production: RSA_public_decrypt(signature, public_key, hash)
 // Then compare hashes

 unsigned char decrypted_sig[256];
 for (int i = 0; i < 256; i++) {
 decrypted_sig[i] = cert->signature[i] ^ ca_public_key[i];
 }

 // Check if hash matches
 if (memcmp(decrypted_sig, computed_hash.hash, SHA256_SIZE) == 0) {
 return 1; // Valid signature
 }
 return 0; // Invalid signature
}

// ============================================
// Certificate Validation
// ============================================

int validate_certificate(Certificate *cert) {
 time_t now = time(NULL);

 // Check 1: Validity period
 if (now < cert->valid_from) {
 printf("[ERROR] Certificate not yet valid\n");
 return 0;
 }

 if (now > cert->valid_until) {
 printf("[ERROR] Certificate has expired\n");
 return 0;
 }

 // Check 2: Issuer is trusted (simplified)
 if (strcmp(cert->issuer, "TrustedCA") != 0) {
 printf("[ERROR] Certificate not issued by trusted CA\n");
 return 0;
 }

 return 1;
}

// ============================================
// Main PKI Demonstration
// ============================================

int main() {
 printf("========================================\n");
 printf("PKI Public Key Distribution Demo (C)\n");
 printf("========================================\n");

 // Step 1: CA generates its key pair
 printf("\n[Step 1] CA generates key pair...\n");
 unsigned char ca_private_key[256], ca_public_key[256];

 // Simulated key generation
 for (int i = 0; i < 256; i++) {
 ca_private_key[i] = (unsigned char)(i * 7 + 42);
 ca_public_key[i] = (unsigned char)(i * 13 + 17);
 }
 printf(" CA private key generated (simulated)\n");
 printf(" CA public key distributed with browser (trust store)\n");

 // Step 2: Bob creates his key pair
 printf("\n[Step 2] Bob generates key pair...\n");
 unsigned char bob_private_key[256], bob_public_key[256];
 for (int i = 0; i < 256; i++) {
 bob_private_key[i] = (unsigned char)(i * 11 + 23);
 bob_public_key[i] = (unsigned char)(i * 17 + 31);
 }
 memcpy(bob_public_key, bob_public_key, 256); // Store as certificate's public key
 printf(" Bob's key pair generated\n");

 // Step 3: CA creates Bob's certificate
 printf("\n[Step 3] CA creates Bob's certificate...\n");
 Certificate bob_cert;
 init_certificate(&bob_cert, "Bob", "TrustedCA");
 memcpy(bob_cert.public_key, bob_public_key, RSA_KEY_SIZE);

 // CA signs the certificate
 sign_certificate(&bob_cert, ca_private_key);
 print_certificate_info(&bob_cert);

 // Step 4: Alice receives and verifies Bob's certificate
 printf("[Step 4] Alice verifies Bob's certificate...\n");

 // First, validate basic fields
 if (validate_certificate(&bob_cert)) {
 printf(" Certificate dates are valid\n");
 }

 // Then verify CA's signature
 if (verify_certificate_signature(&bob_cert, ca_public_key)) {
 printf(" ✓ CA signature verified!\n");
 printf(" ✓ Bob's public key is authentic\n");
 printf(" ✓ Secure communication can begin\n");
 } else {
 printf(" ✗ Signature verification FAILED!\n");
 printf(" ✗ Certificate may be tampered or fake\n");
 }

 // Step 5: Demonstrate attack detection
 printf("\n[Step 5] Testing tamper detection...\n");
 Certificate fake_cert;
 init_certificate(&fake_cert, "Mallory", "TrustedCA");
 // Sign with attacker's key (not CA's key)
 unsigned char attacker_key[256];
 for (int i = 0; i < 256; i++) attacker_key[i] = (unsigned char)(i * 99);
 sign_certificate(&fake_cert, attacker_key);

 if (verify_certificate_signature(&fake_cert, ca_public_key)) {
 printf(" ✗ Fake certificate accepted!\n");
 } else {
 printf(" ✓ Attack detected: Certificate rejected!\n");
 }

 printf("\n========================================\n");
 printf("Summary: Public key securely bound to identity\n");
 printf(" via CA-signed X.509 certificate\n");
 printf("========================================\n");

 return 0;
}
